insert into public.mock_test_results (id, mock_test_id, student_id, scores, total_score, teacher_note, created_at) values (gen_random_uuid(), 'a3372e8b-3925-4f87-8d80-b4504e95e729', 'fd985660-1303-4265-8814-8b9f3a287484', '{"Listening":4,"Reading":21}'::jsonb, 25, 'Nắm rất vững nền tảng ngữ pháp cơ bản, đặc biệt là vị trí và chức năng của các từ loại (danh, tính, trạng từ), cách sử dụng đại từ linh hoạt, cùng với giới từ và từ vựng theo ngữ cảnh.', '2026-05-28T14:21:11.000Z') on conflict (mock_test_id, student_id) do nothing;
insert into public.mock_test_results (id, mock_test_id, student_id, scores, total_score, teacher_note, created_at) values (gen_random_uuid(), 'a3372e8b-3925-4f87-8d80-b4504e95e729', '5541d7cb-a327-4bc7-8408-010d069a9e8f', '{"Listening":1,"Reading":10}'::jsonb, 11, 'Nắm khá tốt các kiến thức cơ bản về vị trí của tính từ bổ nghĩa cho danh từ, trạng từ bổ nghĩa cho tính từ, tính từ đứng sau động từ liên kết và giới từ chỉ địa điểm.
insert into public.mock_test_results (id, mock_test_id, student_id, scores, total_score, teacher_note, created_at) values (gen_random_uuid(), 'a3372e8b-3925-4f87-8d80-b4504e95e729', 'dac49642-cbc2-4a77-b34f-65cfb031f83c', '{"Listening":2,"Reading":12}'::jsonb, 14, '- Nắm rất chắc kiến thức cơ bản, nhận diện tốt các cặp từ loại đi liền kề nhau như tính từ bổ nghĩa cho danh từ, trạng từ bổ nghĩa cho tính từ, cùng với từ vựng, giới từ cơ bản và đại từ phản thân.
insert into public.mock_test_results (id, mock_test_id, student_id, scores, total_score, teacher_note, created_at) values (gen_random_uuid(), 'a3372e8b-3925-4f87-8d80-b4504e95e729', '9816822c-5dd5-4b8a-acb5-d2c5a412631b', '{"Listening":3,"Reading":23}'::jsonb, 26, '- nắm rất vững nền tảng ngữ pháp cơ bản, đặc biệt là vị trí và chức năng của các từ loại (danh, tính, trạng từ), cách sử dụng đại từ linh hoạt, cùng với giới từ và từ vựng theo ngữ cảnh.
insert into public.mock_test_results (id, mock_test_id, student_id, scores, total_score, teacher_note, created_at) values (gen_random_uuid(), 'a3372e8b-3925-4f87-8d80-b4504e95e729', '2bf99992-94f9-48c2-953c-a8819e8a4342', '{"Listening":2,"Reading":12}'::jsonb, 14, '- nắm rất vững các kiến thức nền tảng ở phần cơ bản, nhận diện tốt đại từ chủ ngữ, tính từ sở hữu, giới từ chỉ địa điểm và các cặp từ loại đi liền kề
insert into public.mock_test_results (id, mock_test_id, student_id, scores, total_score, teacher_note, created_at) values (gen_random_uuid(), 'a3372e8b-3925-4f87-8d80-b4504e95e729', '40cc83fe-ddac-4867-920e-a616ef2a6c49', '{"Listening":3,"Reading":17}'::jsonb, 20, '- nắm rất chắc các phần ngữ pháp cốt lõi ở phần cơ bản, xử lý tốt cấu trúc giả định với tính từ, đại từ sở hữu/phản thân, giới từ chỉ nơi chốn và từ vựng theo ngữ cảnh.
insert into public.mock_test_results (id, mock_test_id, student_id, scores, total_score, teacher_note, created_at) values (gen_random_uuid(), 'a3372e8b-3925-4f87-8d80-b4504e95e729', '94478a44-7c2f-4ee7-a827-fd3212fb47a0', '{"Listening":3,"Reading":13}'::jsonb, 16, '- Nắm khá tốt các kiến thức nền tảng ở phần cơ bản, đặc biệt là cách nhận diện vị trí từ loại khi đứng liền kề nhau (tính từ đứng trước bổ nghĩa cho danh từ, trạng từ bổ nghĩa cho tính từ) và phân biệt tốt đại từ sở hữu/đại từ phản thân.
insert into public.mock_test_results (id, mock_test_id, student_id, scores, total_score, teacher_note, created_at) values (gen_random_uuid(), 'a3372e8b-3925-4f87-8d80-b4504e95e729', '7b8243d5-8540-4b7f-bbef-9da4627d7794', '{"Listening":2,"Reading":15}'::jsonb, 17, '- Nắm khá ổn các cấu trúc có dấu hiệu nhận biết rõ ràng như giới từ chỉ nơi chốn, đại từ nhân xưng làm chủ ngữ, đại từ phản thân/sở hữu, tính từ đứng sau cấu trúc "It is" hoặc "become", và danh từ đứng sau lượng từ hoặc tính từ.
